#include <bits/stdc++.h>
using namespace std;
const int maxn=105;
int n,q,dp[maxn][maxn];
vector<pair<int,int>> g[maxn];
void dfs(int u,int fa){
	for(auto e:g[u]){
		int v=e.first,w=e.second;
		if(v==fa){
			continue;
		}
		dfs(v,u);
		for(int j=q;j>=0;j--){
			for(int k=0;k<=j-1;k++){
				dp[u][j]=max(dp[u][j],dp[u][j-k-1]+dp[v][k]+w);
			}
		}
	}
}
int main(){
	ios::sync_with_stdio(0),cin.tie(0),cout.tie(0);
	cin>>n>>q;
	for(int i=1;i<n;i++){
		int a,b,w;
		cin>>a>>b>>w;
		g[a].emplace_back(b,w);
		g[b].emplace_back(a,w);
	}
	dfs(1,0);
	cout<<dp[1][q];
	return 0;
}
